    "GOTY_CONTENDER" BOOLEAN NOT NULL,
    "HOURS_PLAYED" INTEGER,
    "PLATINUM_TROPHY" BOOLEAN NOT NULL,
    "PRICE_PAID_EUR" NUMERIC(8, 2),
    "PURCHASE_DATE" DATE,
    "RATING" INTEGER,
    "RECOMMEND_TO_FRIEND" BOOLEAN NOT NULL,
    "RELEASE_YEAR" INTEGER,
    "REPLAY_VALUE" INTEGER,
    "SOUNDTRACK_SCORE" INTEGER,
    "STARTED_DATE" DATE,
    "STORY_SCORE" INTEGER,
    "VISUALS_SCORE" INTEGER,
    "ADDED_BY_ID" BIGINT,
    "CREATED_AT" TIMESTAMP(6),
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 11) NOT NULL,
    "UPDATED_AT" TIMESTAMP(6),
    "CURRENT_BUILD" CHARACTER VARYING(100),
    "DEVELOPER" CHARACTER VARYING(100),
    "MAIN_PROTAGONIST" CHARACTER VARYING(100),
    "PUBLISHER" CHARACTER VARYING(100),
    "MOOD_TAGS" CHARACTER VARYING(200),
    "TITLE" CHARACTER VARYING(200) NOT NULL,
    "FAVORITE_MOMENT" CHARACTER VARYING(500),
    "PERSONAL_NOTES" CHARACTER VARYING(2000),
    "REVIEW" CHARACTER VARYING(2000),
    "DIFFICULTY" ENUM('EASY', 'HARD', 'NIGHTMARE', 'NORMAL', 'SOULSBORNE', 'STORY'),
    "GENRE" ENUM('ACTION_RPG', 'BATTLE_ROYALE', 'FIGHTING', 'FPS', 'GRAND_STRATEGY', 'INDIE', 'METROIDVANIA', 'MMORPG', 'MOBA', 'OPEN_WORLD', 'PLATFORMER', 'PUZZLE', 'RACING', 'ROGUELIKE', 'RPG', 'SHOOTER', 'SIMULATION', 'SOULSLIKE', 'SPORTS', 'STRATEGY', 'SURVIVAL', 'SURVIVAL_HORROR', 'VISUAL_NOVEL') NOT NULL,
    "PLATFORM" ENUM('BROWSER', 'MOBILE_ANDROID', 'MOBILE_IOS', 'PC_EPIC', 'PC_GAMEPASS', 'PC_GOG', 'PC_STEAM', 'PS4', 'PS5', 'RETRO_HANDHELD', 'STEAM_DECK', 'SWITCH', 'VR_PSVR', 'VR_QUEST', 'XBOX_ONE', 'XBOX_SERIES') NOT NULL,
    "PLAY_STYLE" ENUM('COMPLETIONIST', 'CO_OP_COUCH', 'CO_OP_ONLINE', 'MMO_GUILD', 'PVP_CASUAL', 'PVP_COMPETITIVE', 'SOLO', 'SPEEDRUN'),
    "SECONDARY_GENRE" ENUM('ACTION_RPG', 'BATTLE_ROYALE', 'FIGHTING', 'FPS', 'GRAND_STRATEGY', 'INDIE', 'METROIDVANIA', 'MMORPG', 'MOBA', 'OPEN_WORLD', 'PLATFORMER', 'PUZZLE', 'RACING', 'ROGUELIKE', 'RPG', 'SHOOTER', 'SIMULATION', 'SOULSLIKE', 'SPORTS', 'STRATEGY', 'SURVIVAL', 'SURVIVAL_HORROR', 'VISUAL_NOVEL'),
    "STATUS" ENUM('ABANDONED', 'BACKLOG', 'BEATEN', 'COMPLETED_100', 'ON_HOLD', 'PLAYING', 'REPLAYING', 'WISHLIST') NOT NULL
);         
